function rotateImage(data) {
    const lines = data.trim().split('\n');
    const n = parseInt(lines[0]);
    const matrix = lines.slice(1).map(line => line.split(' ').map(Number));
    const newMatrix = Array.from({ length: n }, () => Array(n).fill(0));

    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            newMatrix[j][n - 1 - i] = matrix[i][j];
        }
    }

    return newMatrix.map(row => row.join(' ')).join('\n');
}

