class Solution {
    public void rotateImage(int[][] data) {
        int n = data.length;
        // Transpose the matrix
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int temp = data[i][j];
                data[i][j] = data[j][i];
                data[j][i] = temp;
            }
        }
        // Reverse each row
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n / 2; j++) {
                int temp = data[i][j];
                data[i][j] = data[i][n - 1 - j];
                data[i][n - 1 - j] = temp;
            }
        }
    }
}

