#include <vector>
#include <string>
using namespace std;
class Solution {
    public:
    void rotateImage(vector<vector<int>>& data) {
        int n = data.size();
        // Transpose the matrix
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                swap(data[i][j], data[j][i]);
            }
        }
        // Reverse each row
        for (int i = 0; i < n; i++) {
            reverse(data[i].begin(), data[i].end());
        }
    }
}
